import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import { tripsAPI } from '../services/api';

const features = [
  {
    icon: '🗺️',
    title: 'Last Trip Recap',
    desc: 'View where you went, who came along, how long you stayed, and every memory from your most recent adventure.',
    color: 'from-orange-100 to-amber-50',
    accent: 'text-orange-500',
  },
  {
    icon: '📅',
    title: 'Upcoming Trips',
    desc: 'See all your planned trips at a glance — dates, destinations, and who\'s joining you next.',
    color: 'from-blue-100 to-sky-50',
    accent: 'text-blue-500',
  },
  {
    icon: '💸',
    title: 'Trip Spending',
    desc: 'Track how much you spent on each trip — food, stays, transport — split by member or total.',
    color: 'from-primary-100 to-emerald-50',
    accent: 'text-primary-600',
  },
  {
    icon: '👥',
    title: 'Trip Members',
    desc: 'See who joined each trip, manage your travel crew, and split costs between friends easily.',
    color: 'from-purple-100 to-fuchsia-50',
    accent: 'text-purple-500',
  },
  {
    icon: '📸',
    title: 'Trip Timeline',
    desc: 'A day-by-day breakdown of your trip — activities, places visited, and notes you left yourself.',
    color: 'from-rose-100 to-pink-50',
    accent: 'text-rose-500',
  },
  {
    icon: '📊',
    title: 'Travel Stats',
    desc: 'How many trips this year, total days traveled, countries visited, and your total spend over time.',
    color: 'from-teal-100 to-cyan-50',
    accent: 'text-teal-600',
  },
];

export default function LandingPage() {
  const { user } = useAuth();
  const [trips, setTrips] = useState([]);
  const [loadingTrips, setLoadingTrips] = useState(true);

  useEffect(() => {
    if (!user) {
      setLoadingTrips(false);
      return;
    }
    const fetchTrips = async () => {
      try {
        const data = await tripsAPI.getAll();
        setTrips(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoadingTrips(false);
      }
    };
    fetchTrips();
  }, [user]);

  // Derive preview card data from real trips
  const today = new Date();

  const lastTrip = trips
    .filter(t => new Date(t.endDate) < today)
    .sort((a, b) => new Date(b.endDate) - new Date(a.endDate))[0];

  const nextTrip = trips
    .filter(t => new Date(t.startDate) > today)
    .sort((a, b) => new Date(a.startDate) - new Date(b.startDate))[0];

  const totalSpent = trips.reduce((sum, t) => sum + (t.totalSpent || 0), 0);
  const totalMembers = trips.reduce((sum, t) => sum + (t.memberCount || 1), 0);
  const perPersonAvg = totalMembers > 0 ? Math.round(totalSpent / totalMembers) : 0;

  const getDuration = (trip) => {
    if (!trip) return 0;
    const diff = Math.ceil((new Date(trip.endDate) - new Date(trip.startDate)) / (1000 * 60 * 60 * 24)) + 1;
    return isNaN(diff) || diff < 0 ? 0 : diff;
  };

  const previewCards = [
    {
      label: 'Last Trip',
      value: lastTrip?.destination || 'No trips yet',
      sub: lastTrip ? `${getDuration(lastTrip)} days · ${lastTrip.memberCount || 1} members` : 'Plan your first one',
      icon: lastTrip?.emoji || '🏔️',
      gradient: 'from-orange-400 to-amber-500',
      offset: '',
    },
    {
      label: 'Total Spent',
      value: `₹${totalSpent.toLocaleString()}`,
      sub: totalMembers > 0 ? `₹${perPersonAvg.toLocaleString()} per person` : 'Across all trips',
      icon: '💸',
      gradient: 'from-primary-500 to-emerald-500',
      offset: 'ml-6',
    },
    {
      label: 'Next Trip',
      value: nextTrip?.destination || 'Nothing planned',
      sub: nextTrip
        ? `${new Date(nextTrip.startDate).toLocaleDateString(undefined, { month: 'long', day: 'numeric' })} · ${nextTrip.memberCount || 1} members`
        : 'Start planning',
      icon: nextTrip?.emoji || '🏖️',
      gradient: 'from-blue-500 to-indigo-500',
      offset: 'ml-2',
    },
  ];

  const tripsThisYear = trips.filter(t => new Date(t.startDate).getFullYear() === today.getFullYear()).length;

  return (
    <div className="min-h-screen bg-white">
      {/* Hero */}
      <section className="pt-28 pb-10 px-6 relative overflow-hidden">
        {/* ... background decorations unchanged ... */}
        <div className="max-w-7xl mx-auto relative z-10">
          <div className="grid md:grid-cols-2 gap-14 items-center">
            {/* Left side unchanged */}

            {/* Right — staggered preview cards */}
            <div className="relative flex justify-center items-center animate-fade-in-up animate-fill-both animate-delay-200">
              {user && loadingTrips ? (
                <div className="w-full max-w-sm flex items-center justify-center h-64">
                  <div className="w-8 h-8 border-4 border-primary-200 border-t-primary-500 rounded-full animate-spin" />
                </div>
              ) : (
                <div className="relative w-full max-w-sm flex flex-col gap-4 animate-float">
                  {previewCards.map((card, i) => (
                    <div
                      key={i}
                      className={`bg-white rounded-2xl shadow-xl border border-gray-100 p-5 flex items-center gap-4 ${card.offset}`}
                    >
                      <div className={`w-12 h-12 rounded-2xl bg-gradient-to-br ${card.gradient} flex items-center justify-center text-2xl flex-shrink-0 shadow-md`}>
                        {card.icon}
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 font-medium uppercase tracking-wide">{card.label}</p>
                        <p className="font-display font-bold text-gray-800 text-lg leading-tight truncate max-w-[180px]">{card.value}</p>
                        <p className="text-xs text-gray-400 mt-0.5">{card.sub}</p>
                      </div>
                    </div>
                  ))}

                  {/* floating badge */}
                  <div className="absolute -top-3 -right-3 bg-white rounded-2xl shadow-lg border border-gray-100 px-3 py-2 flex items-center gap-2">
                    <span className="text-lg">🎉</span>
                    <div>
                      <p className="text-xs font-semibold text-gray-700">
                        {user ? `${tripsThisYear} trips this year` : '8 trips this year'}
                      </p>
                      <p className="text-xs text-gray-400">Keep exploring!</p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </section>

      {/* What you can track */}
      <section id="features" className="py-10 px-6">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-10">
            <p className="text-primary-600 font-semibold text-sm uppercase tracking-widest mb-3">Built for you & your friends</p>
            <h2 className="font-display text-4xl font-bold text-gray-900">
              Everything about your trips,
              <br />
              <span className="text-primary-600">all in one place</span>
            </h2>
          </div>

          <div className="grid md:grid-cols-3 gap-6">
            {features.map((f, i) => (
              <div
                key={i}
                className={`bg-gradient-to-br ${f.color} rounded-2xl p-6 border border-white hover:shadow-xl transition-all duration-300 hover:-translate-y-1 group`}
              >
                <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-2xl mb-4 shadow-md group-hover:scale-110 transition-transform">
                  {f.icon}
                </div>
                <h3 className="font-display font-bold text-xl text-gray-800 mb-2">{f.title}</h3>
                <p className="text-sm text-gray-600 leading-relaxed">{f.desc}</p>
                <button className={`mt-4 text-sm font-semibold ${f.accent} flex items-center gap-1 hover:gap-2 transition-all`}>
                  Learn More <span>→</span>
                </button>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Strip */}
      <section id='community' className="py-16 bg-gradient-to-r from-primary-600 to-emerald-500 relative overflow-hidden">
        <div className="absolute inset-0 opacity-10">
          <div className="absolute top-0 left-0 w-full h-full"
            style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '40px 40px' }} />
        </div>
        <div className="max-w-7xl mx-auto px-6 relative z-10">
          <div className="text-center mb-10">
            <h2 className="font-display text-3xl font-bold text-white">Built around how you actually travel</h2>
            <p className="text-primary-100 mt-2">Simple, personal, and just for your group</p>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {[
              { icon: '✈️', value: 'Trips', desc: 'Log every trip you take' },
              { icon: '👥', value: 'Members', desc: 'Add friends per trip' },
              { icon: '💰', value: 'Spending', desc: 'Track costs & splits' },
              { icon: '📍', value: 'Places', desc: 'Save every destination' },
            ].map((s) => (
              <div key={s.value} className="text-center bg-white/10 backdrop-blur-sm rounded-2xl p-5 border border-white/20">
                <div className="text-3xl mb-2">{s.icon}</div>
                <div className="font-display font-bold text-xl text-white">{s.value}</div>
                <div className="text-primary-100 text-sm mt-1">{s.desc}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* How it works */}
      <section id='how-it-works' className="py-20 px-6 bg-gray-50">
        <div className="max-w-4xl mx-auto">
          <div className="text-center mb-14">
            <p className="text-primary-600 font-semibold text-sm uppercase tracking-widest mb-3">Simple flow</p>
            <h2 className="font-display text-4xl font-bold text-gray-900">How it works</h2>
          </div>
          <div className="grid md:grid-cols-3 gap-8">
            {[
              { step: '01', icon: '✏️', title: 'Create a Trip', desc: 'Add a trip name, destination, dates, and invite your friends to join.' },
              { step: '02', icon: '💸', title: 'Log Expenses', desc: 'Add what you spent — food, stays, fuel — and see the total split per person.' },
              { step: '03', icon: '📖', title: 'Relive It', desc: 'After the trip, revisit the timeline, spending summary, and who was there.' },
            ].map((step, i) => (
              <div key={i} className="bg-white rounded-2xl p-6 border border-gray-100 hover:shadow-xl transition-all duration-300 hover:-translate-y-1 text-center group">
                <div className="text-xs font-bold text-primary-500 tracking-widest mb-3">{step.step}</div>
                <div className="w-14 h-14 bg-primary-50 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4 group-hover:scale-110 transition-transform">
                  {step.icon}
                </div>
                <h3 className="font-display font-bold text-lg text-gray-800 mb-2">{step.title}</h3>
                <p className="text-sm text-gray-500 leading-relaxed">{step.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="py-20 px-6">
        <div className="max-w-3xl mx-auto text-center">
          <div className="bg-gradient-to-br from-primary-600 to-emerald-500 rounded-3xl p-12 relative overflow-hidden">
            <div className="absolute inset-0 opacity-10"
              style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '30px 30px' }} />
            <div className="relative z-10">
              <p className="text-4xl mb-4">🧳</p>
              <h2 className="font-display text-4xl font-bold text-white mb-4">Ready to log your trips?</h2>
              <p className="text-primary-100 mb-8 text-lg">Start tracking your travels — past, present, and upcoming.</p>
              <div className="flex flex-wrap justify-center gap-4">
                {!user ? (
                  <button
                    onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
                    className="px-8 py-3.5 bg-white text-primary-600 font-bold rounded-xl hover:bg-primary-50 transition-all shadow-lg hover:shadow-xl text-sm"
                  >
                    Create Your Account →
                  </button>
                ) : (
                  <Link
                    to="/dashboard"
                    className="px-8 py-3.5 bg-white text-primary-600 font-bold rounded-xl hover:bg-primary-50 transition-all shadow-lg hover:shadow-xl text-sm"
                  >
                    Go to My Trips →
                  </Link>
                )}
                <a href="#features" className="px-8 py-3.5 bg-white/20 border border-white/30 text-white font-semibold rounded-xl hover:bg-white/30 transition-all text-sm backdrop-blur-sm">
                  See Features
                </a>
              </div>
            </div>
          </div>
        </div>
      </section>

<footer className="bg-gray-900 text-gray-400 py-10 px-6">
  <div className="max-w-7xl mx-auto">
    <div className="flex flex-col md:flex-row justify-between items-center gap-6 pb-6 border-b border-gray-800">
      <div className="flex items-center gap-2.5">
        <div className="w-8 h-8 bg-gradient-to-br from-primary-500 to-emerald-600 rounded-xl flex items-center justify-center">
          <span className="text-white text-sm">✈</span>
        </div>
        <span className="font-display font-bold text-white text-lg">Trip<span className="text-primary-400">Nest</span></span>
      </div>
      <p className="text-sm text-gray-500">
        Designed & developed by <span className="text-white font-medium">Sowndhar</span>
      </p>
      <p className="text-sm text-gray-500">
        Built exclusively for <span className="text-primary-400 font-medium">FF Cabins</span>
      </p>
    </div>
    <p className="text-center text-xs text-gray-600 mt-6">
      © 2026 TripNest. All rights reserved. · Exclusively for FF Cabins.
    </p>
  </div>
</footer>
    </div>
  );
}
